#include <bits/stdc++.h>
using namespace std;
const int N=200005,INF=1e9+5;
vector<int> v;
map<int,int> mp;
int log_n,n,pos[2*N],nxt[N][20],mn[2*N];
struct node
{
    int l,r,id;
} a[N];
struct Node
{
    int num,id;
    bool operator<(const Node other) const
    {
        return num<other.num;
    }
};
bool cmp1(node x,node y)
{
    return x.l<y.l;
}
bool cmp2(node x,node y)
{
    return x.id<y.id;
}
int fun(int l,int r)
{
    int ans=0;
    for(int i=log_n;i>=0;i--)
    {
        if(a[nxt[l][i]].r<=r)
        {
            ans+=(1<<i);
            l=nxt[l][i];
        }
    }
    return ans;
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n;
    log_n=log2(n);
    for(int i=1;i<=n;i++)
    {
        int l,r;
        cin>>l>>r;
        v.push_back(l);
        v.push_back(r);
        a[i]=node{l,r,i};
    }
    sort(v.begin(),v.end());
    int len=unique(v.begin(),v.end())-v.begin()-1;
    for(int i=0;i<=len;i++)
    {
        mp[v[i]]=i+1;
    }
    len++;
    for(int i=1;i<=n;i++)
    {
        a[i].l=mp[a[i].l];
        a[i].r=mp[a[i].r];
    }
    sort(a+1,a+1+n,cmp1);
    a[n+1]=node{INF,INF,n+1},a[0]=node{-INF,-INF,0};
    memset(mn,0x3f,sizeof(mn));
    mn[len+1]=len+1;
    pos[len+1]=n+1;
    for (int i=n;i>=1;i--)
    {
        if(mn[a[i].l]>a[i].r)
        {
            mn[a[i].l]=a[i].r,pos[a[i].l]=a[i].id;
        }
    }
    for(int i=len;i>=1;i--)
    {
        if(mn[i]>mn[i+1])
        {
            mn[i]=mn[i+1],pos[i]=pos[i+1];
        }
    }
    nxt[n+1][0]=n+1;
    for(int i=1;i<=n;i++)
    {
        nxt[a[i].id][0]=pos[a[i].r+1];
    }
    nxt[0][0]=pos[1];
    for(int i=1;i<=log_n;i++)
    {
        for(int j=0;j<=n+1;j++)
        {
            nxt[j][i]=nxt[nxt[j][i-1]][i-1];
        }
    }
    sort(a+1,a+1+n,cmp2);
    int ans1=fun(0,INF-1);
    cout<<ans1<<"\n";
    set<Node> s;
    s.insert(Node{-INF,0}),s.insert(Node{INF,n+1});
    for(int i=1;i<=n;i++)
    {
        auto it=s.upper_bound(Node{a[i].r,0});
        auto it2=s.upper_bound(Node{a[i].l,0});
        if(it!=it2) continue;
        Node rr=*it;
        it--;
        Node ll=*it;
        if(fun(ll.id,a[i].l-1)+fun(i,rr.num-1)+1!=fun(ll.id,rr.num-1)) continue;
        cout<<i<<" ";
        s.insert(Node{a[i].l,a[i].id});
        s.insert(Node{a[i].r,a[i].id});
    }
    return 0;
}
